var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일단 대본을 받긴 했는데, 아무리 리허설이라도 무대에 서려니까 긴장되네.","JPN":"とりあえず台本はもらったけど、急に舞台に立つって考えたら\\n緊張してくるね。","ENG":"I got the script, but I'm getting nervous about going up on stage for the rehearsal.","TWN":"雖然是有拿到劇本，但畢竟是要上台，還是有點緊張呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"신호가 왔어, 이제 무대로 나가면 되나?","JPN":"合図だ。もう舞台に上がればいいのかな？","ENG":"That's my cue. Do I go up on stage now?","TWN":"打Pass了，現在出場嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"줄리엣! 내, 내가 돌아왔다네. 그동안 잘 지냈나?","JPN":"ジュリエット！　ぼ、僕が帰ってきた。元気だったか？","ENG":"Juliet! I-it is my lady, O, it is my love!","TWN":"茱麗葉！我，我回來了，你過得好嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"로미오, 이렇게 다시 만나서 정말로 기쁘군요.","JPN":"ロミオ、こうして再びお会いできて本当に嬉しいです。","ENG":"O, Romeo, how camest thou hither, tell me, and wherefore?","TWN":"羅密歐，我好開心還能再見到你。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어라, 회장? 여기서는…….","JPN":"あれ、会長？　ここは……","ENG":"Y-Yen? That's not the next line...","TWN":"嗯？會長？這裡要……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"정말로 기쁘군요, 로미오. 이렇게 제 앞에 다시 모습을 드러내시다니!","JPN":"ああ、心から嬉しいです、ロミオ。\\nこのように私の前に再び姿を現すなんて！","ENG":"By whose direction found’st thou out this place?","TWN":"羅密歐，我好開心，你竟然敢再次出現在我面前！"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우, 우왓! 무슨 짓이야!","JPN":"うわっ！　何してるの！？","ENG":"W-whoa! What are you doing?!","TWN":"哇啊！你幹嘛！"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"무슨 말씀이시죠? 이 저택에 발을 들였을 때부터 목숨을 버릴 각오는 하셨을 텐데요?","JPN":"何のことでしょう？　この邸宅に再び足を踏み入れたということは、\\n命を捨てる覚悟をなさったのでは？","ENG":"And the place death, considering who thou art.","TWN":"什麼幹嘛？當你踏入這棟房子時，應該就已經做好赴死的心理準備吧？"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고? 내가 받은 대본에서는……!","JPN":"ええ？　私の台本にはそんな……！","ENG":"What? That's not in my script...!","TWN":"赴死？可是我收到的劇本……！"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"못 본 사이에 잡담이 느셨군요. 유언은 그게 전부인가요?","JPN":"見ない間に饒舌な方になりましたね。遺言はそれだけでしょうか？","ENG":"Thou pratest far too much, dost thou not see? Are those thy parting words, thy final plea?","TWN":"這麼久不見，你的話變多了呢。這就是你最後的遺言嗎？"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니! 처음부터 명백한 NG잖아! 연극부 애들은 대체 뭘 하고 있는 거야?","JPN":"いやいやいや！　これは明らかにNGでしょ！\\n演劇部は何してるの？","ENG":"No! This was obviously wrong from the start! What the heck is the theater club doing?!","TWN":"拜託！剛才不是已經NG了嗎！戲劇部的人怎麼都不喊卡？"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고!? 애드리브로 진행하라고!? 그게 무슨!?","JPN":"は？　アドリブで続けろって！？　どういうこと！？","ENG":"WHAT?! You want me to improvise the whole thing?!","TWN":"什麼！？要我即興發揮！？胡說八道什麼！？"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"서운하군요, 로미오. 절 두고 어딜 보시는 거죠?","JPN":"寂しいですわ、ロミオ。\\n私を放っておいて、どこに目を向けているのですか？","ENG":"O, Romeo, wilt thou leave me so unsatisfied?","TWN":"真令人難過。羅密歐，你為何轉頭不看我呢？"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아. 이렇게 된 이상…… 나도 내 마음대로 애드리브 해주겠어!","JPN":"よし、こうなった以上……私も勝手にアドリブでやっていくからね！","ENG":"All right. If this is what you want... I'll make my own lines too!","TWN":"好吧，既然如此……那我也要來即興發揮囉！"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L29_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"진심이에요 부장? 저 둘에게 각각 다른 대본을 줬다고요!?","JPN":"本気ですか、部長？　二人にそれぞれ違う台本を渡したんですか？","ENG":"You can't be serious! You gave them different scripts on purpose?!","TWN":"社長，你是說真的嗎？她們二個人拿到的是不同的劇本嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"아까 뭘 들었어? 화려한 연출만 보여줄 수 있다면, 스토리 같은 건 아무래도 좋다구.","JPN":"さっきの話を聞いてないの？\\n華やかな演出さえ見せられるなら、ストーリーなんてどうでもいいのよ。","ENG":"Didn't you hear what I said? If we can put on a brilliant performance, the story doesn't matter at all!","TWN":"我剛怎麼說的？只要有華麗的大場面，劇情怎麼樣根本無所謂。"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"저길 봐, 두 사람 다 대본 같은 게 없어도 알아서 연기에 몰두하고 있잖아?","JPN":"あれを見なさい。\\n二人とも台本なんか無くても演技に没頭しているじゃない？","ENG":"Look! Those two are in character despite getting completely different scripts!","TWN":"你們看，她們二個就算沒有劇本，也可以投入在演出中不是嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"어…… 저걸 연기라고 하기에는…….","JPN":"えーと……あれを演技というには……","ENG":"Uh... But can you really call that acting...?","TWN":"呃……那算是演出嗎……"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"진정해, 회장! 왜 그렇게 진지한 거야? 이건 그냥 리허설일 뿐이잖아!","JPN":"落ち着いて、会長！　どうしてそこまで真剣にやるの！？\\nただのリハーサルでしょ！","ENG":"Yen, calm down! Why are you so committed to this? It's just a rehearsal!","TWN":"會長，你冷靜點！你這麼認真幹嘛？這只是彩排而已欸！"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저는 언제나 모든 일에 최선을 다하죠.","JPN":"私は常にすべてに対して最善を尽くしています。","ENG":"I always give it my all to whatever task I am doing.","TWN":"我對每件事都全力以赴。"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오히려 되묻고 싶군요, 로미오. 그러는 당신은 왜 제게 진심을 보여주지 않는 거죠?","JPN":"むしろ問い返したいですね、ロミオ。\\nそんなあなたはどうして私に本気を見せてくれないのですか？","ENG":"I should ask thee a similar question, Romeo. Why don't thou reveal thy true self to me?","TWN":"我倒想問問你，羅密歐。為什麼你卻不肯對我認真呢？"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"큭! 회장이 완전히 배역에 빠졌어! 이대로라면…….","JPN":"くっ！　会長が完全に役に入り込んでる！　このままじゃ……","ENG":"Kgh! She's totally immersed in her role! At this rate...","TWN":"唔！會長整個入戲太深！再這樣下去……"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"우와아! 지금 회장이 검 휘두르는 거 봤어? 도대체 1초에 몇 번이나 휘두른 거야?","JPN":"うわあ！　今、会長が剣を振るのを見た？\\nいったい1秒に何回振っていたんだ？","ENG":"Whoa! Did you see Ms. Lanchester swing her sword? How many times was that in just a second?","TWN":"哇啊啊！有看到會長在揮劍嗎？她一秒是揮幾下啊？"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"전학생이 들고 있는 저 무기말이야, 휘두를 때마다 뭔가 불꽃처럼 번쩍거리지 않아?","JPN":"転校生が持っている武器って、振るたびになんか火花みたいなものが光ってない？","ENG":"And when the transfer student swings hers, don't you see something flashing, like sparks?","TWN":"還有轉學生拿的武器，每次揮動的時候都會有火花欸？"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"정말이네? 뭔가 CG 같은 특수 연출인가!?","JPN":"本当だ。CGみたいな特殊演出かな！？","ENG":"You're right! Is it like a special effects thing?!","TWN":"真的欸？這是什麼CG特效嗎！？"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"부장! 부장 말대로예요! 관객들 반응이 엄청 뜨거워요!","JPN":"部長！　部長の言ったとおりでした！　観客の反応が熱いです！","ENG":"You were right! The audience is loving the performance!","TWN":"社長！真的跟你說的一樣欸！觀眾的反應超熱烈的！"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"대단해! 저, 부장이 말했던 연극이라는 걸 왠지 조금 이해할 수 있을 것 같아요!","JPN":"素晴らしい！　私、部長が話していた演劇というものを、少しは理解できた気がします！","ENG":"Amazing! I think I now understand the kind of play you wanted to show!","TWN":"好厲害！我好像可以稍微明白社長所謂的戲劇是怎麼回事了！"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"그래! 이거야! 이런 장면이 필요했어! 회장과 전학생이 진심으로 맞붙는 모습이!","JPN":"そうでしょう、そうでしょう。どうしても必要だったの。\\n会長と転校生が、本気で相まみえることが！","ENG":"This is perfect! We needed a scene like this! An epic clash between Ms. Lanchester and the transfer student engaging in battle!","TWN":"沒錯！就是這樣！這就是我要的大場面！會長跟轉學生認真對打的場面！"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이걸로 확실히 알았어요, 로미오. 당신은 여전히 당신의 본심을 숨기고 있어요.","JPN":"これで確信しました、ロミオ。\\nあなたは相変わらず自分の本心を隠しています。","ENG":"Now it is undeniable, O, Romeo. Thou yet conceal thy true self.","TWN":"羅密歐，我終於明白了，你還是對我藏起你的真心。"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 말이야, 내가 뭘 숨기고 있다고?","JPN":"何の話？　私が何を隠しているって？","ENG":"What does that mean? What am I concealing?","TWN":"你到底在說什麼？我藏什麼啦？"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"감당할 수 없는 엄청난 힘……. 그 리미트를 깨면, 저를 쓰러트릴 수도 있겠죠.","JPN":"手に負えないような凄まじい力……\\nその限界を破れば、私を倒すこともできるでしょう。","ENG":"A power beyond thy control... If thou art break the limit, then thou shall be able to defeat me.","TWN":"無法承受的巨大力量……只要突破極限，就能夠打倒我。"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 저도 가만히 그걸 지켜보고 있지는 않을 겁니다.","JPN":"しかし、こちらもそれを黙って見ているわけにはいきませんので。","ENG":"However, I will not just stand back and watch.","TWN":"但我也不會坐以待斃的。"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"자, 로미오. 다음 합으로 저의 진심을 보여드리죠.","JPN":"さあ、ロミオ。次の攻撃で私の本気をお見せします。","ENG":"Now, Romeo. When our swords collide once more, I shall reveal my heart.","TWN":"來吧，羅密歐，讓你看看我的真心。"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아, 회장이 그렇게까지 말한다면 나도…….","JPN":"よし、会長がそこまで言うなら私だって……","ENG":"Okay. If that's what you're gonna do, Yen, then I'll also–","TWN":"很好，既然會長這麼說，那我也……"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"얼레……? 이게…… 원래 손잡이가 움직였던가?","JPN":"あれ……？　これって……元々取っ手が動くものだったっけ？","ENG":"Huh...? Did... the grip move like that?","TWN":"嗯……？這……把手本來就會動嗎？"},"stage":{"bg":"HALL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>……</color>","JPN":"<color=#ffd34c>……</color>","ENG":"<color=#ffd34c>...</color>","TWN":"<color=#ffd34c>……</color>"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>Wolvesbane Unlock</color>","JPN":"<color=#ffd34c>Wolvesbane Unlock</color>","ENG":"<color=#ffd34c>Wolvesbane Unlock</color>","TWN":"<color=#ffd34c>Wolvesbane Unlock</color>"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>제 2종 정보 오염을 관측했습니다. 오염된 정보를 복구합니다.</color>","JPN":"<color=#ffd34c>第2種情報汚染を観測しました。汚染された情報を復旧します。</color>","ENG":"<color=#ffd34c>Category 2 data corruption detected. Recovering corrupted data.</color>","TWN":"<color=#ffd34c>觀測到2類情報汙染，復原遭汙染的情報。</color>"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 기억들은……? 설마……!?","JPN":"この記憶は……？　まさか……！？","ENG":"These memories...? Are they...?!","TWN":"這些記憶是……？難道……！？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래, 이제야 알겠어.","JPN":"そう……やっとわかった。","ENG":"Now I understand.","TWN":"我知道了。"},"stage":{"bg":"CA_YOOMINA_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기는…… 이 학교는…… 우리가 원래 있던 곳이 아니야.","JPN":"ここは……この学校は……私たちが元々いた場所じゃない。","ENG":"This place... This school... It's not where we are from.","TWN":"這個地方……這間學校……都不是我們原本所在的地方。"},"stage":{"bg":"CA_YOOMINA_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우리가 원래 있던 곳은……!","JPN":"私たちがいた場所は……！","ENG":"The place we are originally from is...!","TWN":"我們原本所在的地方是……！"},"stage":{"bg":"CA_YOOMINA_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"굉장해 연극부!! 가슴이 뛰는 최고의 대결이었어!!","JPN":"すごいぞ、演劇部！！　胸が震える最高の対決だった！！","ENG":"Bravo, theater club!! That was the best battle scene ever!!","TWN":"戲劇部好強！！令人屏息的精彩對決！！"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"감동적인 승부였어, 전학생!! 거기서 마지막에 검을 뽑을 줄이야!!","JPN":"感動的な勝負だったよ、転校生！！　最後のあの場面で剣を抜くとは！！","ENG":"What a fight, transfer student!! I never thought you'd pull out your sword at the last moment!","TWN":"打得好精彩！轉學生！！沒想到你會在最後的時候拔劍！！"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"란체스터 회장도 멋졌어요!! 리허설은 아쉬웠지만, 내일은 이길 수 있을 거예요!!","JPN":"ランチェスター会長もとてもかっこよかったです！！\\nリハーサルでは惜しかったですけど、次は勝てますよ！！","ENG":"Ms. Lanchester! You were great too!! Though you lost in the rehearsal, I'm sure you'll win in the fight tomorrow!!","TWN":"蘭賈斯特會長也好帥！！雖然彩排的時候輸掉，但你明天一定會贏的！！"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"졌습니다. 미나 양. 정말로 대단한 연기로군요.","JPN":"一本取られましたね、ミナさん。実に素晴らしい演技でした。","ENG":"I admit my defeat, Mina. That was truly an astounding performance.","TWN":"我輸了，米娜，你演得很好。"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하, 하하. 그런데 이걸로 괜찮을까?","JPN":"は、はは……でも、これでよかったの？","ENG":"Hah, hah hah. But will this be acceptable?","TWN":"哈哈，可是這樣沒關係嗎？"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우리 때문에 무대도 엉망이 되고, 어쩐지 결말도 흐지부지 넘어 갔잖아.","JPN":"私たちのせいで舞台がめちゃくちゃになって、\\nなんだか結末も中途半端に終わったような気がするけど。","ENG":"The stage is a mess because of us, and the ending was underwhelming, to say the least.","TWN":"我們把舞台搞成這樣，結局也脫稿演出。"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요. 하지만 결과적으로 관객분들이 만족하시면 괜찮은 것 아닐까요?","JPN":"そうですね。\\nしかし結果的に観客の皆様が満足しているなら、悪くないと思います。","ENG":"I see. But it should be fine as long as the audience is satisfied.","TWN":"是嗎？不過以結果而言，觀眾喜歡的話應該就沒關係吧？"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"……으으 박수 소리? 어라?","JPN":"拍手？　うう……、あら？","ENG":"...Err... Hmm? Applause?","TWN":"……呃，掌聲？怎麼回事？"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"쟤네들 무대에서 뭘 하고 있는 거야? 진짜 칼을 쓰다가 다치면 어쩌자는 거야?","JPN":"あの子たち、舞台で何をやっているの？\\n真剣を使うなんて、怪我をしたらどうするの！？","ENG":"What are they doing up on the stage? Using real swords? But that's so dangerous...!","TWN":"她們在搞什麼？怎麼可以在台上揮劍？要是傷到人的話怎麼辦？"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"무슨 소리에요? 저건 전부 부장의 지시대로……","JPN":"何を言っているんですか？　全部部長の指示で……","ENG":"Huh? But you're the one who told them to use them...","TWN":"社長，你在說什麼？這全都是照你說的……"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"내 지시라고?","JPN":"私の指示？","ENG":"I approved that?","TWN":"照我說的？"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"네, 연출만 화려하면 스토리따위는 아무 상관 없다고 하셨잖아요.","JPN":"ええ。新しい台本で、演出が華やかなら、\\nストーリーなんてどうでもいいって……","ENG":"Yes. You said that if they put on a brilliant performance, the story didn't matter at all.","TWN":"對啊，是你說只要有華麗的大場面，劇情根本無所謂。"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"그럴 리가 없잖아! 내일 대본은 원래대로 진행해!","JPN":"そんなワケないでしょう。\\n明日の本番は、きっちり元の台本でやらないと！","ENG":"There's no way I would say that! We stick with the script tomorrow!","TWN":"這怎麼可能！明天要照原訂的劇本進行！"},"stage":{"bg":"GRONIA_HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어라? 연극부 쪽이 뭔가 소란스러운 것 같은데…….","JPN":"あら？　なんだか、揉めてるみたいだけど……","ENG":"Huh? Looks like something's going on over at the theater club...","TWN":"嗯？戲劇部的人不知道在吵什麼……"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 결과만 좋으면 됐나?","JPN":"まあ、結果オーライか。","ENG":"Well, at least the results were good, right?","TWN":"至少結果是好的吧？"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미나 양. 전보다 상쾌한 표정이 되었군요.","JPN":"ミナさん、前よりスッキリした顔つきになりましたね。","ENG":"Mina, you look more refreshed than before.","TWN":"米娜 ，你的臉色好多了呢。"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 회장 덕분에 잊어버렸던 것을 떠올릴 수 있었거든.","JPN":"うん、会長のおかげで忘れていたことを思い出せたんだ。","ENG":"Yeah, thanks to you, I was reminded of something I had forgotten.","TWN":"嗯，拜會長所賜，我才能想起遺忘的事。"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"잊어버렸던 것?","JPN":"忘れていたことですか？","ENG":"Something you had forgotten?","TWN":"遺忘的事？"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맞아. 정말 소중한 것……. 어쨌든 고마워 회장.","JPN":"そう。とても大切なこと。とにかくありがとう、会長。","ENG":"Yeah. It's something really precious to me... Anyway, thanks, Yen.","TWN":"沒錯，真正重要的事……總之，謝謝會長。"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 녀석을 만나러 가자. 아마 그 녀석이라면 처음부터 알고 있었을 거야. 그렇다면……!","JPN":"さあ、彼に会いに行かないと。\\nたぶんあいつは最初から気付いていたんだ。だから……！","ENG":"I have to go talk to him. I'm positive that he knew everything from the start. Then that means...!","TWN":"去找那傢伙吧，說不定他從頭到尾都知情。若是如此……！"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};